## 5. GraphQL Controller / Service 구현 예시

**파일 위치:** `graphql/src/main/kotlin/com/maum/backend/controller/call/CallController.kt`

```kotlin
@Controller
class CallController(
    private val callService: CallService,
) {
    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun startCallMatching(
        @UserId userId: String,
        @Argument input: StartCallMatchingInput,
    ): CallMatchResult {
        val response = callService.startCallMatching(userId, input)
        return response.toCallMatchResult()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun cancelCallMatching(
        @UserId userId: String,
        @Argument sessionId: String,
    ): Boolean {
        val response = callService.cancelCallMatching(userId, sessionId)
        return response.success
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun currentCallSession(
        @UserId userId: String,
    ): CallSessionResponse? {
        val response = callService.getCurrentCallSession(userId)
        return response.session?.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myCallHistory(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<CallHistoryResponse> {
        val response = callService.listCallHistory(userId, limit ?: 20, offset ?: 0)
        return response.itemsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun endCallSession(
        @UserId userId: String,
        @Argument input: EndCallSessionInput,
    ): CallSessionResponse {
        val response = callService.endCallSession(userId, input.sessionId)
        return response.session.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun rateCall(
        @UserId userId: String,
        @Argument input: RateCallInput,
    ): Boolean {
        val response = callService.rateCall(userId, input)
        return response.success
    }
}
```

**파일 위치:** `graphql/src/main/kotlin/com/maum/backend/service/call/CallService.kt`

```kotlin
@Service
class CallService {
    @GrpcClient("call-grpc")
    private lateinit var stub: CallServiceGrpc.CallServiceBlockingStub

    fun startCallMatching(userId: String, input: StartCallMatchingInput): StartCallMatchingResponse {
        val request = StartCallMatchingRequest.newBuilder()
            .setCallerUserId(userId)
            .setMatchType(input.matchType.toProto())
            .apply { input.targetUserId?.let { setTargetUserId(it) } }
            .build()
        return try {
            stub.startCallMatching(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun cancelCallMatching(userId: String, sessionId: String): CancelCallMatchingResponse {
        val request = CancelCallMatchingRequest.newBuilder()
            .setUserId(userId)
            .setSessionId(sessionId)
            .build()
        return try {
            stub.cancelCallMatching(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun getCurrentCallSession(userId: String): GetCurrentCallSessionResponse {
        val request = GetCurrentCallSessionRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getCurrentCallSession(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun listCallHistory(userId: String, limit: Int, offset: Int): ListCallHistoryResponse {
        val request = ListCallHistoryRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            stub.listCallHistory(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun endCallSession(userId: String, sessionId: String): EndCallSessionResponse {
        val request = EndCallSessionRequest.newBuilder()
            .setUserId(userId)
            .setSessionId(sessionId)
            .build()
        return try {
            stub.endCallSession(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun rateCall(userId: String, input: RateCallInput): RateCallResponse {
        val request = RateCallRequest.newBuilder()
            .setUserId(userId)
            .setSessionId(input.sessionId)
            .setMannerScore(input.mannerScore)
            .apply { input.comment?.let { setComment(it) } }
            .build()
        return try {
            stub.rateCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

---

## 6. 일관성 검증 체크리스트

| 항목 | 규칙 | 적용 여부 |
|------|------|-----------|
| Type 명 | PascalCase | `CallSession`, `CallMatchResult` - 준수 |
| Input 명 | `{Action}{Domain}Input` | `StartCallMatchingInput`, `RateCallInput` - 준수 |
| Query 명 | 조회 동사 (get, list, my) | `currentCallSession`, `myCallHistory` - 준수 |
| Mutation 명 | 행위 동사 (start, cancel, end, rate) | 준수 |
| 인증 | `@PreAuthorize("hasAuthority('User')")` | 전 endpoint 적용 |
| 사용자 ID | `@UserId userId: String` | 전 Controller 적용 |
| Proto 필드명 | `snake_case` | `caller_user_id`, `session_id` - 준수 |
| Proto 서비스명 | `{Domain}Service` | `CallService` - 준수 |
| Proto enum 접두사 | `{ENUM_NAME}_` | `CALL_STATUS_WAITING` - 준수 |
| Catalog | `maum` (call 도메인) | entity 정의 시 적용 필요 |

---

## 7. 영향 범위 (변경 시 영향받는 레이어)

```
신규 생성 대상:
- protobuf/src/main/proto/call/call_service.proto          (신규)
- graphql/src/main/resources/graphql/call.graphqls          (신규)
- graphql/.../controller/call/CallController.kt             (신규)
- graphql/.../service/call/CallService.kt                   (신규)
- {call-module}/.../controller/CallGrpcService.kt           (신규)
- {call-module}/.../service/CallSessionService.kt           (신규)
- domain/.../entity/call/CallSessionEntity.kt               (신규)
- domain/.../repository/call/CallSessionRepository.kt       (신규)

기존 연관 모듈:
- user 모듈: SimpleUser 타입 조회 (partnerUser, callerUser 필드)
- follow 모듈: 친구 매칭 시 관계 검증 필요
- notification 모듈: 매칭 완료/통화 요청 알림 연동 필요
```

---

## 8. 개발 순서 (develop/SKILL.md 준수)

```
1. CallSessionEntity         → domain/.../entity/call/
2. CallSessionRepository     → domain/.../repository/call/
3. call.graphqls             → graphql/.../resources/graphql/
4. call_service.proto        → protobuf/.../proto/call/
   └── ./gradlew :protobuf:build
5. CallSessionService        → call-module/.../service/
6. CallGrpcService           → call-module/.../controller/
7. CallService (gRPC Client) → graphql/.../service/call/
8. CallController            → graphql/.../controller/call/
```

---

이 설계는 Maum 앱의 핵심 기능인 음성 통화 매칭 플로우를 완전히 커버하며, 프로젝트의 GraphQL 컨벤션(`PascalCase` 타입, `{Action}{Domain}Input` 입력, `@PreAuthorize` 인증)과 gRPC 컨벤션(`snake_case` 필드, `{Method}Request/Response` 메시지, Proto3 `optional` 키워드)을 모두 준수합니다. `SimpleUser` 타입은 기존 user 도메인에서 재사용하여 일관성을 유지합니다.

