## 5. GraphQL Controller / Service 구현 예시

**파일 위치:** `graphql/src/main/kotlin/com/maum/backend/controller/call/CallController.kt`

```kotlin
@Controller
class CallController(
    private val callService: CallService,
) {
    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun startCallMatching(
        @UserId userId: String,
        @Argument input: StartCallMatchingInput,
    ): CallMatchResult {
        val response = callService.startCallMatching(userId, input)
        return response.toCallMatchResult()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun cancelCallMatching(
        @UserId userId: String,
        @Argument sessionId: String,
    ): Boolean {
        val response = callService.cancelCallMatching(userId, sessionId)
        return response.success
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun currentCallSession(
        @UserId userId: String,
    ): CallSessionResponse? {
        val response = callService.getCurrentCallSession(userId)
        return response.session?.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myCallHistory(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<CallHistoryResponse> {
        val response = callService.listCallHistory(userId, limit ?: 20, offset ?: 0)
        return response.itemsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun endCallSession(
        @UserId userId: String,
        @Argument input: EndCallSessionInput,
    ): CallSessionResponse {
        val response = callService.endCallSession(userId, input.sessionId)
        return response.session.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun rateCall(
        @UserId userId: String,
        @Argument input: RateCallInput,
    ): Boolean {
        val response = callService.rateCall(userId, input)
        return response.success
    }
}
